import redis
from redis import StrictRedis

class RedisCache():
    def __init__(self, host='localhost', port=6379, db=0):
        self.host = host
        self.port = port
        self.db = db
        self.redis_client = StrictRedis(host=self.host, port=self.port, db=self.db)

    def set_session_token(self, session_token):
        self.redis_client.set('session_token', session_token)

    def get_session_token(self):
        return self.redis_client.get('session_token')

    def set_api_key(self, api_key):
        self.redis_client.set('api_key', api_key)

    def get_api_key(self):
        return self.redis_client.get('api_key')

    def expire_session_token(self, ttl=60):
        self.redis_client.expire('session_token', ttl)

    def expire_api_key(self, ttl=60):
        self.redis_client.expire('api_key', ttl)